#!/usr/bin/env bash
# M42.6 — CI guard: every generated Foundry artifact carries its
# generation-input identity.
#
# Invariant: any file generated by the Code Foundry templates MUST have
# a comment header (within the first 8 lines) that names:
#
#   - the generator version (e.g. "Generator: code-foundry-0.2.0")
#   - the template version  (e.g. "Template:  springboot-template-0.1.0")
#   - the spec hash         (e.g. "Spec hash: sha256:<hex>")
#   - the IR hash           (e.g. "IR hash:   sha256:<hex>")
#
# Plus, where present, a `generation-manifest.json` at the run root
# whose `specHash` matches every file's header `Spec hash`.
#
# This prevents two failure modes:
#   1. A template change accidentally drops the header → loses the link
#      from a file on disk back to the spec that produced it. (Patent
#      Chain E receipt chain collapses if any file lacks identity.)
#   2. Two files from different specs landing in the same `gen/` tree
#      (a stale generation mixed with a fresh one). The hash check
#      catches that.
#
# The guard is opt-in per repository — it scans `gen/` and `.workspace/`
# trees if present; absence of those trees is not a failure.

set -euo pipefail

ROOT="$(cd "$(dirname "${BASH_SOURCE[0]}")/.." && pwd)"
cd "$ROOT"

fail=0
inspected=0

# Patterns we consider "generated source files" — every stack stamps
# the same canonical comment block at file top.
SOURCE_GLOBS=(
  "*.java"
  "*.py"
  "*.ts"
  "*.tsx"
  "*.yml"
  "*.yaml"
)

# Roots to scan. The Foundry CLI writes to /workspace/<runId>/ inside
# the container; the host-side gen/ is the conventional output root
# for CI-mirrored generation.
SCAN_ROOTS=(
  "gen"
  "singularity-code-foundry/gen"
  "singularity-code-foundry/apps/code-foundry-api/.workspace"
)

require_header_line() {
  local file="$1"
  local pattern="$2"
  if ! head -n 8 "$file" | grep -q -E "$pattern"; then
    echo "FAIL $file — missing header line matching: $pattern" >&2
    fail=1
  fi
}

check_file() {
  local file="$1"
  inspected=$((inspected + 1))
  require_header_line "$file" "Generator: code-foundry-"
  require_header_line "$file" "Template:[[:space:]]+[a-zA-Z0-9._-]+"
  require_header_line "$file" "Spec hash: sha256:[a-f0-9]+"
  require_header_line "$file" "IR hash:[[:space:]]+sha256:[a-f0-9]+"
}

# Cross-check: every file in a run root must reference the same specHash
# as that run's generation-manifest.json (when one exists).
check_run_consistency() {
  local run_root="$1"
  local manifest="$run_root/generation-manifest.json"
  if [ ! -f "$manifest" ]; then
    return 0
  fi
  local declared
  declared=$(python3 -c "
import json, sys
with open('$manifest') as f:
    m = json.load(f)
print(m.get('specHash') or '')
" 2>/dev/null || echo "")
  if [ -z "$declared" ]; then
    echo "WARN $manifest has no specHash; skipping cross-check." >&2
    return 0
  fi
  while IFS= read -r -d '' file; do
    local in_file
    in_file=$(head -n 8 "$file" | grep -E "Spec hash: sha256:" | head -n1 | sed -E 's/.*Spec hash:[[:space:]]+(sha256:[a-f0-9]+).*/\1/')
    if [ -n "$in_file" ] && [ "$in_file" != "$declared" ]; then
      echo "FAIL $file declares $in_file but $manifest declares $declared" >&2
      fail=1
    fi
  done < <(
    for glob in "${SOURCE_GLOBS[@]}"; do
      find "$run_root" -type f -name "$glob" -print0 2>/dev/null
    done
  )
}

for root in "${SCAN_ROOTS[@]}"; do
  if [ ! -d "$root" ]; then
    continue
  fi
  # Each immediate child of the scan root is a run directory.
  while IFS= read -r -d '' run_dir; do
    while IFS= read -r -d '' file; do
      check_file "$file"
    done < <(
      for glob in "${SOURCE_GLOBS[@]}"; do
        find "$run_dir" -type f -name "$glob" -print0 2>/dev/null
      done
    )
    check_run_consistency "$run_dir"
  done < <(find "$root" -mindepth 1 -maxdepth 1 -type d -print0 2>/dev/null)
done

if [ "$fail" -ne 0 ]; then
  echo "" >&2
  echo "✗ codegen-manifest guard FAILED — inspected $inspected file(s)." >&2
  exit 1
fi

echo "✓ codegen-manifest guard passed ($inspected file(s) inspected)."
